import cadquery as cq
import math

# Spring parameters inferred from the image
R = 12.5        # Mean radius of the helix
r = 2.0         # Wire radius
P = 9.0         # Pitch (vertical distance between turns)
N = 4.0         # Number of active coils
H_hook = 11.0   # Vertical extension height of the hooks

# Precompute coefficients for the cubic polynomial used for Z-axis hook transitions
# This guarantees C1 continuity (smooth tangents) where the hooks meet the helix
A = P / (2 * math.pi)
B = (3 * H_hook - 2 * A * math.pi) / math.pi**2
C = (A * math.pi - 2 * H_hook) / math.pi**3

def get_x(theta):
    if theta < 0:
        return R * math.cos(theta / 2) * math.cos(theta)
    elif theta > N * 2 * math.pi:
        d_theta = theta - N * 2 * math.pi
        return R * math.cos(d_theta / 2) * math.cos(theta)
    else:
        return R * math.cos(theta)

def get_y(theta):
    if theta < 0:
        return R * math.cos(theta / 2) * math.sin(theta)
    elif theta > N * 2 * math.pi:
        d_theta = theta - N * 2 * math.pi
        return R * math.cos(d_theta / 2) * math.sin(theta)
    else:
        return R * math.sin(theta)

def get_z(theta):
    if theta < 0:
        return A * theta - B * theta**2 + C * theta**3
    elif theta > N * 2 * math.pi:
        d_theta = theta - N * 2 * math.pi
        return N * P + A * d_theta + B * d_theta**2 + C * d_theta**3
    else:
        return (theta / (2 * math.pi)) * P

def path(t):
    # Map t in [0, 1] to theta range for the entire spring including hooks
    # -1.25*pi and +1.25*pi extend the hooks to curve slightly past the center axis
    theta_min = -1.25 * math.pi
    theta_max = N * 2 * math.pi + 1.25 * math.pi
    theta = theta_min + t * (theta_max - theta_min)
    return (get_x(theta), get_y(theta), get_z(theta))

# Generate points for the spline path
pts = [cq.Vector(*path(i / 400.0)) for i in range(401)]
path_edge = cq.Edge.makeSpline(pts)
path_wire = cq.Wire.assembleEdges([path_edge])

# Calculate exact point and numerical tangent at the start point (t=0)
dt = 1e-5
p0 = path(0.0)
p1 = path(dt)
tangent = (p1[0] - p0[0], p1[1] - p0[1], p1[2] - p0[2])
length = math.sqrt(sum(c**2 for c in tangent))
tangent = tuple(c / length for c in tangent)

# Create the circular profile at the start point, oriented normal to the path
plane = cq.Plane(origin=p0, normal=tangent)
profile = cq.Workplane(plane).circle(r)

# Sweep the profile along the wire path using Frenet frame to prevent twisting
result = profile.sweep(path_wire, isFrenet=True)
